--
-- Sync the default site_settings row (created by DataInitializer) with the
-- real branding used on the original deployment.
--

UPDATE public.site_settings SET
  site_name = 'Labigel coffee',
  primary_color = '#C6A15B',
  secondary_color = '#0D0D0D',
  font_family = 'Poppins',
  instagram_url = 'https://www.instagram.com/labigelbatikent/',
  phone = '+90 544 566 1070',
  address = 'Kardelen, 277 Sokak Batıkent Yolu No:2/1, 06370 Yenimahalle/Ankara',
  about_text = 'Labigel Cafe - Ye, İç, Oyna! En lezzetli atıştırmalıklar ve içecekler burada.'
WHERE id = 1;
